(window.webpackJsonp=window.webpackJsonp||[]).push([[7],{188:function(e,t,a){"use strict";a.r(t);var n=a(0),o=Object(n.a)({},function(){var e=this,t=e.$createElement,a=e._self._c||t;return a("ContentSlotsDistributor",{attrs:{"slot-key":e.$parent.slotKey}},[a("h1",{attrs:{id:"a-little-side-project-🐙"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#a-little-side-project-🐙","aria-hidden":"true"}},[e._v("#")]),e._v(" A little side project 🐙")]),e._v(" "),a("p",[e._v("I always liked playing video games.\nIn my opinion playing games is as good a use of free time as reading a book.\nYou can lose yourself and countless of hours in their made-up worlds and embark on amazing adventures that just aren't possible in the real world.\nInstead of just passively taking it all in, the games are interactive and let you choose what to do next.\nEither you progress the main storyline or spend some time on a silly side quest.")]),e._v(" "),a("p",[e._v("I played a lot of games in all kind of genres.\nThe earliest game I remember playing on PC was a game where the player was supposed to move blocks onto a specific place and then go to another level.\nThe levels were represented as actual floors of a skyscraper and upon loading the game you could choose the level using a numpad next to an elevator door.\nThen came games like Golden Axe, Altered Beast, Prince of Persia, Commander Keen, Wolfenstein 3D, Doom, Duke Nukem 3D and other similar first person shooters of that time.\nAll games I couldn't even finish at that time.")]),e._v(" "),a("p",[e._v("We had a Sega 16-bit Mega Drive II with a demo of a soccer game, a tennis game and a F1 racing game.\nOccasionaly we rented other games for the system, but as we could only keep those for three days, I could extensively play those.\nMeantime I got into Age of Empires, Command & Conquer, Need for Speed 2, Tomb Raider and the likes.")]),e._v(" "),a("p",[e._v("At the age of 10 I finally got a Gameboy (the huge grey one) with the newly released Warioland II.\nNot long after that, I got myself Pokémon Red, a game I told my parents that could never be really finished.\nI played through it multiple times, each time overwriting my save game and my ultimate team with a little sadness.")]),e._v(" "),a("p",[e._v("When I was around 11 years old, a friend of mine had a N64 and started playing The Legend of Zelda: Ocarina of Time.\nI found it amazing and I just wanted to keep playing it, so I convinced my folks to get me a N64 with the game too.\nI remember playing it the moment I got home and my character dying 7 times in the Gohma battle (the first boss that I can now kill in minutes) before I got so sick of it my mom told me to quit the game.\nAfter about an hour I continued the game and beat Gohma on the first try.\nNow able to explore Hyrule Field for the first time, literally a new world opened up for me.\nFollowing the cliché, this game changed my view on how a good game should be.\nThe graphics were nothing I had seen before.\nThere is a main story in which you play a hero destined, against all odds, to save the world.\nI could listen to characters (though they kept repeating themselves) and due to the time travel mechanic, it was amazing to see the effects of young link in the adult timeline.\nLooking back now, there are surely better games, but somehow it's a game I love returning too.\nNaturally, I wanted more of this and I have bought almost every Zelda game since, only skipping Skyward Sword since I didn't like being forced to use motion controls and didn't own a Wii or Wii U.\nI especially loved the little easter eggs in each game, referencing previous games in the installment.")]),e._v(" "),a("p",[e._v("As I got older, my interest in games didn't really lessen.\nThe only thing that lessened was time to play them.\nMy interest in creating a game started to grow, though.\nI studied computer science in college and learned how to program Java-applications and C#-applications, even COBOL, but games was not something talked about.\nThis makes that I have 0 experience in creating games, but I won't let that stop me.\nMy purpose in this, is not to get rich from it, but just to make something fun.\nI'd love to make something different than another freemium or pay-to-win mobile shit game.\nSomething anyone can play at their own speed and discover the easter eggs put into it.")]),e._v(" "),a("p",[e._v("🛡⚔️")])])},[],!1,null,null,null);t.default=o.exports}}]);